'use client';

import React, { useEffect, useState } from 'react';
import { Card, CardHeader, CardTitle, CardContent } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { User, Mail, UserCheck, UserX, Edit2, Trash, ArrowLeft, ArrowRight } from 'lucide-react';
import Link from 'next/link';
// import axios from 'axios';

interface UserType {
  id: string;
  name: string;
  email: string;
  role: 'admin' | 'customer';
}

export default function UsersPage() {
  const [users, setUsers] = useState<UserType[]>([]);
  const [search, setSearch] = useState('');
  const [page, setPage] = useState(1);
  const [totalPages, setTotalPages] = useState(3); // dummy total pages
  const limit = 6;

  useEffect(() => {
    // 🟢 Dummy paginated data
    const dummyUsers: UserType[] = [
      { id: `U-20${page*1}`, name: `User ${page}-1`, email: `user${page}-1@example.com`, role: 'customer' },
      { id: `U-20${page*2}`, name: `User ${page}-2`, email: `user${page}-2@example.com`, role: 'customer' },
      { id: `U-20${page*3}`, name: `Admin ${page}-3`, email: `admin${page}-3@example.com`, role: 'admin' },
      { id: `U-20${page*4}`, name: `User ${page}-4`, email: `user${page}-4@example.com`, role: 'customer' },
      { id: `U-20${page*5}`, name: `User ${page}-5`, email: `user${page}-5@example.com`, role: 'customer' },
      { id: `U-20${page*6}`, name: `User ${page}-6`, email: `user${page}-6@example.com`, role: 'customer' },
    ];
    setUsers(dummyUsers);

    // 🔹 Replace with real API call
    // const token = localStorage.getItem('token');
    // axios.get(`/api/users?page=${page}&limit=${limit}&search=${search}`, { headers: { Authorization: `Bearer ${token}` } })
    //      .then(res => {
    //          setUsers(res.data.users);
    //          setTotalPages(res.data.totalPages);
    //      })
    //      .catch(err => console.error(err));
  }, [page, search]);

  const handleDelete = (id: string) => {
    if (!confirm('Are you sure you want to delete this user?')) return;

    // 🔹 Replace with real API call
    // axios.delete(`/api/users/${id}`, { withCredentials: true })
    //      .then(() => setUsers(prev => prev.filter(u => u.id !== id)))
    //      .catch(err => console.error(err));

    setUsers(prev => prev.filter(u => u.id !== id));
  };

  const filteredUsers = users.filter(
    u => u.name.toLowerCase().includes(search.toLowerCase()) || u.email.toLowerCase().includes(search.toLowerCase())
  );

  const nextPage = () => { if (page < totalPages) setPage(p => p + 1); };
  const prevPage = () => { if (page > 1) setPage(p => p - 1); };

  return (
    <div className="p-6 space-y-6">
      <h1 className="text-2xl font-bold mb-4">Users</h1>

      <Input
        placeholder="Search by name or email..."
        value={search}
        onChange={e => {
          setSearch(e.target.value);
          setPage(1); // reset page on search
        }}
        className="mb-4"
      />

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredUsers.map(user => (
          <Card key={user.id} className="hover:shadow-md transition">
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <User size={20} /> {user.name}
              </CardTitle>
            </CardHeader>
            <CardContent className="space-y-2">
              <p className="flex items-center gap-1"><Mail size={14} /> {user.email}</p>
              <p className="flex items-center gap-1">
                {user.role === 'admin' ? <UserCheck size={14} /> : <UserX size={14} />} {user.role}
              </p>
              <div className="flex justify-end gap-2 mt-3">
                <Link href={`/admin/user/${user.id}`}>
                  <Button size="sm" className="bg-blue-600 hover:bg-blue-700 text-white">
                    <Edit2 size={14} className="mr-1" /> View
                  </Button>
                </Link>
                <Button size="sm" className="bg-red-600 hover:bg-red-700 text-white" onClick={() => handleDelete(user.id)}>
                  <Trash size={14} className="mr-1" /> Delete
                </Button>
              </div>
            </CardContent>
          </Card>
        ))}
      </div>

      {/* Pagination */}
      <div className="flex justify-center items-center gap-3 mt-6">
        <Button variant="outline" onClick={prevPage} disabled={page === 1}>
          <ArrowLeft className="mr-1 w-4 h-4" /> Prev
        </Button>
        {[...Array(totalPages)].map((_, idx) => (
          <Button
            key={idx}
            variant={page === idx + 1 ? 'default' : 'outline'}
            onClick={() => setPage(idx + 1)}
          >
            {idx + 1}
          </Button>
        ))}
        <Button variant="outline" onClick={nextPage} disabled={page === totalPages}>
          Next <ArrowRight className="ml-1 w-4 h-4" />
        </Button>
      </div>
    </div>
  );
}
